import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface PlayerHighlight {
  name: string;
  position: string;
  points: number;
  sparkline: number[];
}

interface TeamRank {
  currentRank: number;
  points: number;
}

interface WidgetData {
  teamRank: TeamRank;
  playerHighlights: PlayerHighlight[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const metaData = response.meta as MetaData;
  const { teamRank, playerHighlights } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: metaData.theme === 'dark' ? '#1E1E1E' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Fantasy League Tracker
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: metaData.primaryColor }}>
              Rank: {teamRank.currentRank}
            </Typography>
            <Typography variant="body2" sx={{ color: metaData.accentColor }}>
              Points: {teamRank.points}
            </Typography>
          </Box>

          <Stack spacing={1.5}>
            {playerHighlights.map((player) => (
              <Box key={player.name}>
                <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 0.5 }}>
                  <Box>
                    <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
                      {player.name}
                    </Typography>
                    <Typography variant="caption" sx={{ color: '#64748B' }}>
                      {player.position}
                    </Typography>
                  </Box>
                  <Box textAlign="right">
                    <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 500 }}>
                      {player.points} pts
                    </Typography>
                  </Box>
                </Stack>
                <LineChart
                  height={40}
                  series={[
                    {
                      data: player.sparkline,
                      color: metaData.accentColor,
                      curve: 'natural',
                      showMark: false,
                    },
                  ]}
                  xAxis={[{ data: player.sparkline.map((_, i) => i), hide: true }]}
                  margin={{ top: 5, bottom: 5, left: 0, right: 0 }}
                  sx={{
                    '& .MuiLineElement-root': {
                      strokeWidth: 1.5,
                    },
                  }}
                />
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
